const url = $input.first().json.body.url;
const lowerUrl = url.toLowerCase();

let platform = 'unknown';
let actorId = '';

if (lowerUrl.includes('facebook.com') || lowerUrl.includes('fb.watch') || lowerUrl.includes('fb.com')) {
  platform = 'facebook';
  actorId = 'apify~facebook-posts-scraper';
} else if (lowerUrl.includes('instagram.com') || lowerUrl.includes('instagr.am')) {
  platform = 'instagram';
  actorId = 'apify~instagram-post-scraper';
} else if (lowerUrl.includes('tiktok.com') || lowerUrl.includes('vm.tiktok')) {
  platform = 'tiktok';
  actorId = 'thenetaji~tiktok-post-scraper';
}

return [{ json: { url, platform, actorId } }];

const items = $input.first().json;
const item = Array.isArray(items) ? items[0] : items;

let recipeText = '';

if (item.message && item.message.text) recipeText += item.message.text + '\n\n';
if (item.text) recipeText += item.text + '\n\n';
if (item.caption) recipeText += item.caption + '\n\n';
if (item.description) recipeText += item.description + '\n\n';

let captionsUrl = '';
if (item.short_form_video_context && item.short_form_video_context.playback_video && item.short_form_video_context.playback_video.captions_url) {
  captionsUrl = item.short_form_video_context.playback_video.captions_url;
}

return [{ json: { recipeText: recipeText.trim(), captionsUrl, hasTranscript: !!captionsUrl } }];

const srtText = String($input.first().json.data || $input.first().json.body || '');
const prevData = $('Extract Text').first().json;

const cleanTranscript = srtText
  .replace(/^\d+$/gm, '')
  .replace(/\d{2}:\d{2}:\d{2},\d{3}\s*-->\s*\d{2}:\d{2}:\d{2},\d{3}/g, '')
  .replace(/\n{2,}/g, ' ')
  .trim();

const fullText = (prevData.recipeText + '\n\nVideo transcript: ' + cleanTranscript).trim();

return [{ json: { recipeText: fullText } }];

